def binary_search_recursive(arr, low, high, x):
  """
  A recursive implementation of binary search.

  Args:
    arr: The sorted array to search.
    low: The starting index of the search range.
    high: The ending index of the search range.
    x: The element to search for.

  Returns:
    The index of the element if found, otherwise -1.
  """
  if high >= low:
    mid = (high + low) // 2

    if arr[mid] == x:
      return mid
    elif arr[mid] > x:
      return binary_search_recursive(arr, low, mid - 1, x)
    else:
      return binary_search_recursive(arr, mid + 1, high, x)

  else:
    return -1


def binary_search_iterative(arr, x):
  """
  An iterative implementation of binary search.

  Args:
    arr: The sorted array to search.
    x: The element to search for.

  Returns:
    The index of the element if found, otherwise -1.
  """
  low = 0
  high = len(arr) - 1

  while low <= high:
    mid = (high + low) // 2

    if arr[mid] == x:
      return mid
    elif arr[mid] < x:
      low = mid + 1
    else:
      high = mid - 1

  return -1


if __name__ == '__main__':
  arr = [2, 3, 4, 10, 40]
  x = 10

  result_recursive = binary_search_recursive(arr, 0, len(arr) - 1, x)
  result_iterative = binary_search_iterative(arr, x)

  if result_recursive != -1:
    print("Element is present at index (recursive)", result_recursive)
  else:
    print("Element is not present in array (recursive)")

  if result_iterative != -1:
    print("Element is present at index (iterative)", result_iterative)
  else:
    print("Element is not present in array (iterative)")
